# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector as mdb
from getpass import getpass

def main():
    # Get MySQL credentials from user input (not recommended in production)
    username = raw_input("Enter your MySql Username : ") 
    password = getpass(prompt="Password: ", stream=None, echo=True )  
    
    cnx = mdb.connect(user=username, passwd=password ,host='localhost', database= 'mysql') # replace with your host and db name if not local 
                                                           
    file_path =  raw_input("Enter the path of datafile: ")  
    
    cursor = cnx.cursor()                    
     
    sql  = "LOAD DATA INFILE '%s' INTO TABLE mytable FIELDS TERMINATED BY ',' ENCLOSED BY '\"'" % file_path  # replace with your table name if not same as in mysql database  
    
    cursor.execute(sql)                     
                                                           
    cnx.commit()                            
     
if __name__ == "__main__":                  
        main()